--
-- Table structure for table `transactions`
--

DROP TABLE IF EXISTS `transactions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `transactions` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `code` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `date` date NOT NULL,
  `customer_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `total` decimal(15,2) NOT NULL,
  `sub_total` decimal(15,2) NOT NULL,
  `total_item` int NOT NULL,
  `type` enum('INTERNAL','OFFLINE','SHOPEEFOOD','GOFOOD','GRABFOOD') COLLATE utf8mb4_unicode_ci NOT NULL,
  `payment_type` enum('QRIS','CASH','GOPAY','SHOPEEPAY','OVO','BANK_TRANSFER') COLLATE utf8mb4_unicode_ci NOT NULL,
  `status` enum('PAID','CANCELED','PENDING') COLLATE utf8mb4_unicode_ci NOT NULL,
  `online_transaction_revenue` decimal(15,2) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `transactions_code_unique` (`code`)
) ENGINE=InnoDB AUTO_INCREMENT=1811 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

